SELECT species_name
FROM taxons
WHERE taxon_id IN (
  SELECT taxon_id 
  FROM citations
);

SELECT COUNT(taxon_id) 
FROM taxons 
WHERE division = 'n';

SELECT common_name 
FROM taxons 
WHERE taxon_id = 1;

SELECT COUNT(user_id)
FROM user_group_memberships
WHERE group_id = 1;

SELECT AVG(max_classification_date) AS average_recent_classification_date
FROM (
  SELECT MAX(classification_date) AS max_classification_date
  FROM taxon_classifications
  GROUP BY taxon_id
) AS recent_classifications;

SELECT user_id
FROM user_group_memberships
WHERE group_id = 0;
